OpCode::GetI => {
    let ra = base + i.arg_a();
    let rb_v = state.get_at(base + i.arg_b()).clone();
    let c = i.arg_c() as i64;
    match state.fast_get_int(&rb_v, c)? {
        Some(v) => state.set_at(ra, v),
        None => {
            let key = LuaValue::Int(c);
            state.set_ci_savedpc(ci, pc);
