760	/// Emit instruction `i`, grow code array as needed, save line info.
761	/// Returns the pc (index) of the new instruction.
762	pub(crate) fn code(
763	    fs: &mut FuncState,
764	    ls: &mut LexState,
765	    state: &mut LuaState,
766	    i: Instruction,
767	) -> Result<i32, LuaError> {
768	    // C: luaM_growvector(fs->ls->L, f->code, fs->pc, f->sizecode, ...)
769	    // PERF(port): Vec::push handles growth
770	    if fs.f.code.len() <= fs.pc as usize {
771	        fs.f.code.resize(fs.pc as usize + 1, Instruction::default());
772	    }
773	    fs.f.code[fs.pc as usize] = i;
774	    fs.pc += 1;
775	    // C: savelineinfo(fs, f, fs->ls->lastline);
776	    savelineinfo(fs, state, ls.lastline)?;
777	    Ok(fs.pc - 1)
778	}
