781	pub(crate) fn code_abck(
782	    fs: &mut FuncState,
783	    ls: &mut LexState,
784	    o: OpCode,
785	    a: u32,
786	    b: u32,
787	    c: u32,
788	    k: u32,
789	) -> Result<i32, LuaError> {
790	    // TODO(port): getOpMode assertion requires luaP_opmodes lookup
791	    debug_assert!(a <= MAXARG_A && b <= MAXARG_B && c <= MAXARG_C && (k & !1) == 0);
792	    // C: luaK_code(fs, CREATE_ABCk(o, a, b, c, k))
793	    // TODO(port): state needs to be threaded from caller; using dummy for now
794	    // TODO(port): code() needs &mut LuaState for savelineinfo/growvector
795	    let instr = Instruction::abck(o, a, b, c, k);
796	    // PORT NOTE: state is not available at this call site in all callers;
797	    // this is a known Phase B issue.  Callers that have state pass it in;
798	    // others will need refactoring.
799	    // For Phase A we call a version that skips growth:
800	    code_no_state(fs, ls, instr)
801	}
