851	// PORT NOTE: `code_no_state` is a Phase A shim — it records the instruction
852	// and bumps pc but skips the Vec growth check that requires &mut LuaState.
853	// Phase B replaces all call sites with `code(fs, ls, state, instr)`.
854	fn code_no_state(
855	    fs: &mut FuncState,
856	    ls: &LexState,
857	    i: Instruction,
858	) -> Result<i32, LuaError> {
859	    // PERF(port): In production, pre-allocate via reserve_or_grow; here we
860	    // rely on Vec's amortised growth.
861	    if fs.f.code.len() <= fs.pc as usize {
862	        fs.f.code.resize(fs.pc as usize + 1, Instruction::default());
863	    }
