    }
    Ok(())
}

/// C: static void lastlistfield(FuncState *fs, ConsControl *cc)
fn lastlistfield(ls: &mut LexState, state: &mut LuaState, cc: &mut ConsControl) -> Result<(), LuaError> {
    if cc.tostore == 0 {
