    pub nactvar: u8,
    /// C: upval — true if some variable in block is an upvalue
    pub upval: bool,
    /// C: isloop — true if this block is a loop body
    pub isloop: bool,
    /// C: insidetbc — true if inside the scope of a to-be-closed variable
    pub insidetbc: bool,
